changeSet.sql:
-- full schema SQL: create database and tables CREATE DATABASE IF NOT EXISTS lms CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci; USE lms;
CREATE TABLE IF NOT EXISTS users ( id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(100) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, full_name VARCHAR(150), email VARCHAR(150) UNIQUE, role ENUM('ADMIN','LIBRARIAN') NOT NULL DEFAULT 'LIBRARIAN', is_active TINYINT(1) NOT NULL DEFAULT 1, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS categories ( id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL UNIQUE, description TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS authors ( id INT AUTO_INCREMENT PRIMARY KEY, first_name VARCHAR(100), last_name VARCHAR(100), full_name VARCHAR(210), bio TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS publishers ( id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(200) NOT NULL UNIQUE, address TEXT, phone VARCHAR(50), email VARCHAR(150), website VARCHAR(255), created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS books ( id INT AUTO_INCREMENT PRIMARY KEY, isbn VARCHAR(20) UNIQUE, title VARCHAR(500) NOT NULL, description TEXT, category_id INT, publisher_id INT, published_year SMALLINT, total_copies INT NOT NULL DEFAULT 1, available_copies INT NOT NULL DEFAULT 1, added_by INT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_books_title (title), INDEX idx_books_isbn (isbn) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE books ADD CONSTRAINT fk_books_category FOREIGN KEY (category_id) REFERENCES categories(id) ON DELETE SET NULL ON UPDATE CASCADE, ADD CONSTRAINT fk_books_publisher FOREIGN KEY (publisher_id) REFERENCES publishers(id) ON DELETE SET NULL ON UPDATE CASCADE, ADD CONSTRAINT fk_books_addedby FOREIGN KEY (added_by) REFERENCES users(id) ON DELETE SET NULL ON UPDATE CASCADE;
CREATE TABLE IF NOT EXISTS book_authors ( book_id INT NOT NULL, author_id INT NOT NULL, PRIMARY KEY (book_id, author_id) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE book_authors ADD CONSTRAINT fk_ba_book FOREIGN KEY (book_id) REFERENCES books(id) ON DELETE CASCADE ON UPDATE CASCADE, ADD CONSTRAINT fk_ba_author FOREIGN KEY (author_id) REFERENCES authors(id) ON DELETE CASCADE ON UPDATE CASCADE;
CREATE TABLE IF NOT EXISTS book_copies ( id BIGINT AUTO_INCREMENT PRIMARY KEY, book_id INT NOT NULL, copy_number INT NOT NULL DEFAULT 1, barcode VARCHAR(100) UNIQUE, status ENUM('AVAILABLE','ISSUED','LOST','MAINTENANCE') NOT NULL DEFAULT 'AVAILABLE', location VARCHAR(200), added_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_copies_book (book_id), INDEX idx_copies_status (status) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE book_copies ADD CONSTRAINT fk_copies_book FOREIGN KEY (book_id) REFERENCES books(id) ON DELETE CASCADE ON UPDATE CASCADE;
CREATE TABLE IF NOT EXISTS members ( id INT AUTO_INCREMENT PRIMARY KEY, member_no VARCHAR(50) NOT NULL UNIQUE, first_name VARCHAR(120) NOT NULL, last_name VARCHAR(120), email VARCHAR(150), phone VARCHAR(50), address TEXT, dob DATE, joined_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, status ENUM('ACTIVE','INACTIVE','BANNED') NOT NULL DEFAULT 'ACTIVE', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_members_name (first_name, last_name), INDEX idx_members_email (email) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS issues ( id BIGINT AUTO_INCREMENT PRIMARY KEY, copy_id BIGINT NOT NULL, book_id INT NOT NULL, member_id INT NOT NULL, issued_by INT, issue_date DATE NOT NULL DEFAULT (CURRENT_DATE()), due_date DATE NOT NULL, return_date DATE DEFAULT NULL, days_kept INT DEFAULT NULL, fine_amount DECIMAL(10,2) NOT NULL DEFAULT 0.00, status ENUM('ISSUED','RETURNED','LOST') NOT NULL DEFAULT 'ISSUED', created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_issues_member (member_id), INDEX idx_issues_copy (copy_id), INDEX idx_issues_status (status) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE issues ADD CONSTRAINT fk_issues_copy FOREIGN KEY (copy_id) REFERENCES book_copies(id) ON DELETE RESTRICT ON UPDATE CASCADE, ADD CONSTRAINT fk_issues_book FOREIGN KEY (book_id) REFERENCES books(id) ON DELETE RESTRICT ON UPDATE CASCADE, ADD CONSTRAINT fk_issues_member FOREIGN KEY (member_id) REFERENCES members(id) ON DELETE RESTRICT ON UPDATE CASCADE, ADD CONSTRAINT fk_issues_issuedby FOREIGN KEY (issued_by) REFERENCES users(id) ON DELETE SET NULL ON UPDATE CASCADE;
CREATE TABLE IF NOT EXISTS app_settings ( `key` VARCHAR(100) PRIMARY KEY, `value` VARCHAR(255) NOT NULL, description TEXT, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
INSERT INTO app_settings (`key`, `value`, description) VALUES ('late_fee_per_day', '0.50', 'Late fee per day in currency units'), ('loan_days_default', '14', 'Default loan period (days)') ON DUPLICATE KEY UPDATE value = VALUES(value);
-- Example admin user placeholder; replace password hash with bcrypt in production INSERT INTO users (username, password_hash, full_name, email, role) VALUES ('admin', '$2a$10$PLACEHOLDER_HASH_REPLACE_ME', 'Administrator', 'admin@example.com', 'ADMIN') ON DUPLICATE KEY UPDATE email = VALUES(email);
